 1	import * as React from 'react';
 2	import {
 3	  Badge,
 4	  ExpandableSection,
 5	  FormHelperText,
 6	  FormSection,
 7	} from '@patternfly/react-core';
 8	import { useFormikContext } from 'formik';
 9	import { useTranslation } from 'react-i18next';
10	import {
11	  AddTriggerFormValues,
12	  TriggerBindingKind,
13	  TriggerBindingParam,
14	} from '../../../types';
15	import TriggerBindingSelector from './TriggerBindingSelector';
16	import './TriggerBindingSection.scss';
17	
18	const TriggerBindingSection: React.FC = () => {
19	  const { t } = useTranslation('plugin__pipelines-console-plugin');
20	  const { setFieldValue } = useFormikContext<AddTriggerFormValues>();
21	  const [bindingVars, setBindingVars] =
22	    React.useState<TriggerBindingParam[]>(null);
23	
24	  const paramPrefix = 'tt.params.';
25	
26	  const updateTriggerBindingVariables = React.useCallback(
27	    (selectedTriggerBinding: TriggerBindingKind) => {
28	      setBindingVars(selectedTriggerBinding.spec.params);
29	      setFieldValue('triggerBinding.resource', selectedTriggerBinding);
30	    },
31	    [setFieldValue],
32	  );
33	
34	  return (
35	    <div className="odc-trigger-binding-section">
36	      <FormSection title={t('Webhook')}>
37	        <TriggerBindingSelector
38	          description={t(
39	            'Select your Git provider type to be associated with the Trigger.',
40	          )}
41	          label={t('Git provider type')}
42	          onChange={updateTriggerBindingVariables}
43	        />
44	        {bindingVars && (
45	          <ExpandableSection
46	            toggleTextExpanded={t('Hide variables')}
47	            toggleTextCollapsed={t('Show variables')}
48	          >
49	            <div className="odc-trigger-binding-section__variable-container">
50	              <p className="odc-trigger-binding-section__variable-descriptor">
51	                {t(
52	                  'The following variables can be used in the Parameters or when created new Resources.',
53	                )}
54	              </p>
55	              {bindingVars.map(({ name }) => (
56	                <Badge
57	                  key={name}
58	                  className="odc-trigger-binding-section__variable-badge"
59	                  isRead
60	                >
61	                  {name}
62	                </Badge>
63	              ))}
64	            </div>
65	            <FormHelperText className="odc-trigger-binding-section__variable-help-text">
66	              {t('Use this format when you reference variables in this form: ')}
67	              <code className="co-code">{`$(${paramPrefix}parameter)`}</code>
68	            </FormHelperText>
69	          </ExpandableSection>
70	        )}
71	      </FormSection>
72	    </div>
73	  );
74	};
75	
76	export default TriggerBindingSection;

